/*
 * Find the Difference
 * Difficulty: Easy
 * Date: 2026-06-09 | Attempts: 1
 * https://leetcode.com/problems/find-the-difference/
 *
 * You are given two strings s and t.
 * 
 * String t is generated by random shuffling string s and then add one more letter at a random position.
 * 
 * Return the letter that was added to t.
 * 
 * &nbsp;
 * Example 1:
 * 
 * Input: s = "abcd", t = "abcde"
 * Output: "e"
 * Explanation: 'e' is the letter that was added.
 * 
 * Example 2:
 * 
 * Input: s = "", t = "y"
 * Output: "y"
 * 
 * &nbsp;
 * Constraints:
 * 
 * 	0 <= s.length <= 1000
 * 	t.length == s.length + 1
 * 	s and t consist of lowercase English letters.
 */

/**
 * Find the extra letter added to string t compared to string s
 * 
 * Approach: Use XOR operation to find the difference
 * - XOR all characters in both strings
 * - Characters that appear in both strings will cancel out (a ^ a = 0)
 * - Only the extra character will remain
 * 
 * Time Complexity: O(n) where n is the length of string t
 * Space Complexity: O(1) - only using a constant amount of extra space
 * 
 * @param {string} s - Original string
 * @param {string} t - String with one extra character
 * @return {string} The extra character
 */
export function findTheDifference(s, t) {
    let result = 0;
    
    // XOR all characters in string s
    for (let i = 0; i < s.length; i++) {
        result ^= s.charCodeAt(i);
    }
    
    // XOR all characters in string t
    for (let i = 0; i < t.length; i++) {
        result ^= t.charCodeAt(i);
    }
    
    // Convert the result back to character
    return String.fromCharCode(result);
}